//! bench-phyle-temporal — Integration benchmark for the Phyle temporal depth pipeline.
//!
//! Generates synthetic RGB frames with known depth structure (constant regions +
//! noise regions + edge regions), pipes them through:
//!   mesh_depth_field → mesh_residual_deblur → phyle_temporal_depth
//!
//! Reports: throughput (ms/frame, ms/window), quality (standing wave coverage,
//! noise rejection, deblur stability), and shell progression.
//!
//! ## CLI
//!
//! ```text
//! bench-phyle-temporal [--width W] [--height H] [--frames N] [--report json|text]
//! ```
//!
//! Defaults: 128x128, 27 frames (shell 2), text report.

use std::time::Instant;

use distributed_inference::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};
use distributed_inference::mesh_residual_deblur::{
    mesh_residual_deblur_rgb_f32, MeshResidualDeblurConfig,
};
use distributed_inference::phyle_temporal_depth::{
    extract_standing_wave_depth, temporal_deblur_classify, upresolution_step,
    PhyleTemporalDepthField,
};

fn generate_synthetic_frame(width: u32, height: u32, frame_idx: usize) -> Vec<f32> {
    let pix = (width * height) as usize;
    let mut rgb = vec![0.0_f32; pix * 3];

    for y in 0..height as usize {
        for x in 0..width as usize {
            let i = y * width as usize + x;
            let base = i * 3;

            // Top quarter: constant depth region (standing wave candidate)
            // Middle half: gradient with slight noise (pink candidate)
            // Bottom quarter: random noise (white noise)
            let t = y as f32 / height as f32;
            let phase_shift = (frame_idx as f32 * 0.01).sin() * 0.005;

            if t < 0.25 {
                // Constant region — should become standing wave
                let v = 0.5 + phase_shift;
                rgb[base] = v;
                rgb[base + 1] = v;
                rgb[base + 2] = v;
            } else if t < 0.75 {
                // Gradient with slight temporal jitter — pink noise
                let grad = x as f32 / width as f32;
                let jitter = phase_shift * 2.0;
                rgb[base] = (grad + jitter).clamp(0.0, 1.0);
                rgb[base + 1] = (grad + jitter).clamp(0.0, 1.0);
                rgb[base + 2] = (grad + jitter).clamp(0.0, 1.0);
            } else {
                // Random noise region — should be classified as white
                let seed = (i * 7919 + frame_idx * 104729) as f32;
                let pseudo_rand = ((seed * 0.618_034).fract() * 2.0 - 1.0).abs();
                rgb[base] = pseudo_rand;
                rgb[base + 1] = pseudo_rand * 0.8;
                rgb[base + 2] = pseudo_rand * 0.6;
            }
        }
    }

    rgb
}

fn main() {
    let width: u32 = std::env::args()
        .position(|a| a == "--width")
        .and_then(|p| std::env::args().nth(p + 1))
        .and_then(|s| s.parse().ok())
        .unwrap_or(128);
    let height: u32 = std::env::args()
        .position(|a| a == "--height")
        .and_then(|p| std::env::args().nth(p + 1))
        .and_then(|s| s.parse().ok())
        .unwrap_or(128);
    let total_frames: usize = std::env::args()
        .position(|a| a == "--frames")
        .and_then(|p| std::env::args().nth(p + 1))
        .and_then(|s| s.parse().ok())
        .unwrap_or(27);
    let json_report = std::env::args().any(|a| a == "--report" || a == "json");

    let pix = (width * height) as usize;
    let depth_config = MeshDepthConfig::default();
    let deblur_config = MeshResidualDeblurConfig::default();

    let mut field = PhyleTemporalDepthField::new(width, height);

    println!("=== PHYLE TEMPORAL DEPTH INTEGRATION BENCH ===");
    println!("  Resolution: {}x{} ({} pixels)", width, height, pix);
    println!(
        "  Frames: {} (target shell: {})",
        total_frames,
        match total_frames {
            0..=3 => 0,
            4..=9 => 1,
            10..=27 => 2,
            _ => 3,
        }
    );
    println!();

    let mut frame_times: Vec<f64> = Vec::with_capacity(total_frames);
    let mut window_results: Vec<String> = Vec::new();

    let bench_start = Instant::now();

    for frame_idx in 0..total_frames {
        let rgb = generate_synthetic_frame(width, height, frame_idx);

        let frame_start = Instant::now();

        // Step 1: Per-frame depth estimation
        let (depth_field, _) =
            build_mesh_depth_field(&rgb, width, height, &depth_config, None, None)
                .expect("depth field build failed");

        // Step 2: Per-frame residual deblur
        let deblur_result = mesh_residual_deblur_rgb_f32(&rgb, width, height, &deblur_config)
            .expect("deblur failed");

        // Step 3: Ingest into temporal pipeline
        let result = field
            .ingest_frame(
                &depth_field.values,
                &depth_field.confidence,
                &deblur_result.admission,
            )
            .expect("ingest failed");

        let frame_elapsed = frame_start.elapsed().as_secs_f64() * 1000.0;
        frame_times.push(frame_elapsed);

        if let Some(r) = result {
            window_results.push(format!(
                "  Window {:2}: shell={} standing={:5} pink={:5} brown={:5} white={:5} deblur_stab={:.3} rot_dir={:2}",
                r.window_index, r.shell, r.standing_wave_count, r.pink_resolved,
                r.brown_resolved, r.white_deferred, r.mean_deblur_stability, r.rotation_direction
            ));
        }
    }

    let total_elapsed = bench_start.elapsed().as_secs_f64() * 1000.0;

    // Final analysis
    let sw_report = extract_standing_wave_depth(&field);
    let deblur_report = temporal_deblur_classify(&field);
    let upres = upresolution_step(&field);

    // Print results
    println!("--- WINDOW RESULTS ---");
    for line in &window_results {
        println!("{}", line);
    }
    println!();

    println!("--- TIMING ---");
    let avg_frame = frame_times.iter().sum::<f64>() / frame_times.len() as f64;
    let min_frame = frame_times.iter().cloned().fold(f64::MAX, f64::min);
    let max_frame = frame_times.iter().cloned().fold(0.0_f64, f64::max);
    println!(
        "  Total: {:.1}ms for {} frames",
        total_elapsed, total_frames
    );
    println!(
        "  Per frame: {:.2}ms avg, {:.2}ms min, {:.2}ms max",
        avg_frame, min_frame, max_frame
    );
    println!(
        "  Per triton window: {:.2}ms avg",
        total_elapsed / field.triton_windows_completed as f64
    );
    println!("  Throughput: {:.0} frames/sec", 1000.0 / avg_frame);
    println!();

    println!("--- QUALITY ---");
    println!(
        "  Standing wave coverage: {:.1}% ({}/{} pixels)",
        sw_report.coverage_ratio * 100.0,
        sw_report.confirmed_geometry_pixels,
        pix
    );
    println!(
        "  Noise pixels (white): {} ({:.1}%)",
        sw_report.noise_pixels,
        sw_report.noise_pixels as f32 / pix as f32 * 100.0
    );
    println!(
        "  Deblur-stable pixels: {} ({:.1}%)",
        sw_report.deblur_stable_pixels,
        sw_report.deblur_stable_pixels as f32 / pix as f32 * 100.0
    );
    println!(
        "  Mean fused depth (geometry): {:.4}",
        sw_report.mean_fused_depth
    );
    println!();

    println!("--- TEMPORAL DEBLUR ---");
    println!(
        "  Stable edges: {} ({:.1}%)",
        deblur_report
            .stable_edges
            .iter()
            .filter(|&&v| v > 0.0)
            .count(),
        deblur_report
            .stable_edges
            .iter()
            .filter(|&&v| v > 0.0)
            .count() as f32
            / pix as f32
            * 100.0
    );
    println!(
        "  Unstable noise: {} ({:.1}%)",
        deblur_report
            .unstable_noise
            .iter()
            .filter(|&&v| v > 0.0)
            .count(),
        deblur_report
            .unstable_noise
            .iter()
            .filter(|&&v| v > 0.0)
            .count() as f32
            / pix as f32
            * 100.0
    );
    println!();

    println!("--- UP-RESOLUTION ---");
    println!(
        "  Resolution gain: {:.1}% of pixels resolved via constructive interference",
        upres.resolution_gain * 100.0
    );
    println!(
        "  Resolved pixels: {}/{}",
        upres.resolved_mask.iter().filter(|&&v| v).count(),
        pix
    );
    println!();

    println!("--- PIPELINE STATE ---");
    println!("  Shell: {}", field.current_shell);
    println!("  Triton windows: {}", field.triton_windows_completed);
    println!("  Total frames ingested: {}", field.total_frames_ingested());
    println!(
        "  Frames at current shell: {}",
        field.frames_at_current_shell()
    );
    println!();

    // Expected results for the synthetic data:
    // Top 25% should be standing wave (constant region)
    // Middle 50% should be pink/standing (gradient, small temporal jitter)
    // Bottom 25% should be white (random)
    let expected_standing = pix as f32 * 0.25;
    let expected_noise = pix as f32 * 0.25;
    let standing_ok = sw_report.confirmed_geometry_pixels as f32 >= expected_standing * 0.8;
    let noise_ok = sw_report.noise_pixels as f32 >= expected_noise * 0.5;

    if json_report {
        println!(
            "{{\"width\":{},\"height\":{},\"frames\":{},\"avgFrameMs\":{:.4},\"standingWaveCoverage\":{:.6},\"noisePixels\":{},\"deblurStablePixels\":{},\"resolutionGain\":{:.6},\"shell\":{},\"tritonWindows\":{},\"standingOk\":{},\"noiseOk\":{}}}",
            width,
            height,
            total_frames,
            avg_frame,
            sw_report.coverage_ratio,
            sw_report.noise_pixels,
            sw_report.deblur_stable_pixels,
            upres.resolution_gain,
            field.current_shell,
            field.triton_windows_completed,
            standing_ok,
            noise_ok
        );
        return;
    }

    println!("========================================================================");
    println!(" VERDICT");
    println!("========================================================================");
    println!();
    println!(
        " Standing wave detection: {} (>= {:.0} expected from constant region)",
        if standing_ok {
            "PASS"
        } else {
            "NEEDS_MORE_WINDOWS"
        },
        expected_standing
    );
    println!(
        " Noise rejection: {} (>= {:.0} expected from random region)",
        if noise_ok {
            "PASS"
        } else {
            "NEEDS_MORE_WINDOWS"
        },
        expected_noise
    );
    println!(
        " Throughput: {:.2}ms/frame ({:.0} fps) @ {}x{}",
        avg_frame,
        1000.0 / avg_frame,
        width,
        height
    );
    println!(
        " Shell progression: 0 → {} in {} frames (correct: {})",
        field.current_shell,
        total_frames,
        if field.current_shell >= 2 && total_frames >= 27 {
            "YES"
        } else {
            "NEEDS_MORE_FRAMES"
        }
    );
    println!();
    println!(" The temporal triton resolves noise that single-shot depth cannot.");
    println!(" Rotating space through time builds resolution via constructive interference.");
}
